# 示例1：自顶向下记忆化搜索 —— 斐波那契数列
from functools import lru_cache

@lru_cache(maxsize=None)  # 自动备忘录装饰器
def fib(n):
    if n <= 1:
        return n
    return fib(n - 1) + fib(n - 2)

# 手动实现备忘录版本
def fib_memo(n, memo=None):
    if memo is None:
        memo = {}
    if n in memo:
        return memo[n]
    if n <= 1:
        return n
    memo[n] = fib_memo(n - 1, memo) + fib_memo(n - 2, memo)
    return memo[n]

# 时间复杂度: O(n), 空间复杂度: O(n)
print(fib_memo(50))  # 12586269025

# 示例3：状态转移 —— 最长公共子序列(LCS)
def lcs(s1, s2):
    m, n = len(s1), len(s2)
    # dp[i][j] 表示 s1[0:i] 和 s2[0:j] 的LCS长度
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                # 字符匹配：LCS长度+1
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                # 字符不匹配：取较大值
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # 回溯构造LCS（可选）
    def reconstruct(i, j):
        if i == 0 or j == 0:
            return ""
        if s1[i - 1] == s2[j - 1]:
            return reconstruct(i - 1, j - 1) + s1[i - 1]
        if dp[i - 1][j] > dp[i][j - 1]:
            return reconstruct(i - 1, j)
        return reconstruct(i, j - 1)

    return dp[m][n], reconstruct(m, n)

print(lcs("ABCBDAB", "BDCABA"))  # 输出: (4, 'BCBA')
